package com.example.oidcclient.controller;

import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.LinkedHashMap;
import java.util.Map;

@RestController
public class HomeController {

    @GetMapping("/")
    public Map<String, Object> home(@AuthenticationPrincipal OidcUser user) {
        Map<String, Object> response = new LinkedHashMap<>();
        response.put("authenticated", user != null);
        if (user != null) {
            response.put("subject", user.getSubject());
            response.put("name", user.getFullName());
            response.put("email", user.getEmail());
            response.put("claims", user.getClaims());
        }
        return response;
    }

    @GetMapping("/public/ping")
    public Map<String, Object> ping() {
        Map<String, Object> response = new LinkedHashMap<>();
        response.put("status", "ok");
        return response;
    }
}

package com.example.oidcclient.session;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.security.web.context.SecurityContextRepository;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.util.Map;

public class OidcSessionClaimsFilter extends OncePerRequestFilter {

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                    HttpServletResponse response,
                                    FilterChain filterChain) throws ServletException, IOException {
        Authentication authentication = org.springframework.security.core.context.SecurityContextHolder.getContext().getAuthentication();
        if (authentication != null && authentication.getPrincipal() instanceof OidcUser oidcUser) {
            request.getSession(true).setAttribute("oidc_claims", oidcUser.getClaims());
        }
        filterChain.doFilter(request, response);
    }
}

package com.example.oidcclient.session;

import jakarta.servlet.http.HttpSession;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;

import java.util.Map;

public class OidcSessionUtil {
    public static void storeUserSession(HttpSession session, OidcUser user) {
        if (session != null && user != null) {
            session.setAttribute("oidc_subject", user.getSubject());
            session.setAttribute("oidc_name", user.getFullName());
            session.setAttribute("oidc_email", user.getEmail());
            session.setAttribute("oidc_claims", user.getClaims());
        }
    }

    @SuppressWarnings("unchecked")
    public static Map<String, Object> getClaims(HttpSession session) {
        Object value = session == null ? null : session.getAttribute("oidc_claims");
        return value instanceof Map ? (Map<String, Object>) value : null;
    }
}